import{_ as i,C as e,o as p,c as l,ag as s,E as t}from"./chunks/framework.CAXxHpAX.js";const m=JSON.parse('{"title":"8. 实时数据处理：Kafka / Flink","description":"围绕事件流、状态、窗口、水位线和一致性理解实时数据系统。","frontmatter":{"title":"8. 实时数据处理：Kafka / Flink","description":"围绕事件流、状态、窗口、水位线和一致性理解实时数据系统。","prev":{"text":"7. 批处理系统：Hive / Spark / Trino","link":"/chapters/07-batch-processing"},"next":{"text":"9. OLAP 数据库：ClickHouse / Doris / DuckDB","link":"/chapters/09-olap-databases"}},"headers":[],"relativePath":"chapters/08-stream-processing.md","filePath":"chapters/08-stream-processing.md"}'),r={name:"chapters/08-stream-processing.md"};function d(o,a,c,h,u,b){const n=e("Mermaid");return p(),l("div",null,[a[0]||(a[0]=s('<h1 id="_8-实时数据处理-kafka-flink" tabindex="-1">8. 实时数据处理：Kafka / Flink <a class="header-anchor" href="#_8-实时数据处理-kafka-flink" aria-label="Permalink to &quot;8. 实时数据处理：Kafka / Flink&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">本章导读</p><p>围绕事件流、状态、窗口、水位线和一致性理解实时数据系统。</p></div><h2 id="本章阅读框架" tabindex="-1">本章阅读框架 <a class="header-anchor" href="#本章阅读框架" aria-label="Permalink to &quot;本章阅读框架&quot;">​</a></h2><table tabindex="0"><thead><tr><th>阅读问题</th><th>本章回答方式</th></tr></thead><tbody><tr><td>这个问题为什么出现？</td><td>从业务增长、数据规模、系统目标或 AI 应用压力切入。</td></tr><tr><td>它解决什么问题？</td><td>提炼为一个核心判断，避免把概念写成孤立定义。</td></tr><tr><td>它不解决什么问题？</td><td>在机制解释和常见误区中说明边界，防止工具崇拜。</td></tr><tr><td>它在真实平台哪里出现？</td><td>放回 PostgreSQL、数仓、批流、OLAP、湖仓、向量、图和治理的演化链路。</td></tr><tr><td>读完要会做什么？</td><td>通过场景案例和实战任务转成可练习的判断。</td></tr></tbody></table>',4)),t(n,{code:"flowchart%20LR%0A%20%20P%5B%22PostgreSQL%20CDC%22%5D%20--%3E%20D%5B%22Debezium%22%5D%0A%20%20D%20--%3E%20K%5B%22Kafka%20Topic%22%5D%0A%20%20K%20--%3E%20F%5B%22Flink%3A%20Window%20%2F%20State%22%5D%0A%20%20F%20--%3E%20C%5B%22ClickHouse%20%2F%20Doris%22%5D%0A%20%20C%20--%3E%20R%5B%22%E5%AE%9E%E6%97%B6%E7%9C%8B%E6%9D%BF%22%5D%0A"}),a[1]||(a[1]=s(`<p>批处理回答过去发生了什么。</p><p>流处理回答正在发生什么。</p><h2 id="问题切入" tabindex="-1">问题切入 <a class="header-anchor" href="#问题切入" aria-label="Permalink to &quot;问题切入&quot;">​</a></h2><p>当订单支付、用户点击、库存变化、风控事件、设备日志不断产生时，数据平台不能总是等到第二天再处理。</p><p>第 7 章的批处理适合每日经营看板、历史回算和离线特征。但有些问题等不到 T+1：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>支付成功后，实时大盘多久能看到？</span></span>
<span class="line"><span>异常订单是否要在几秒内进入风控？</span></span>
<span class="line"><span>库存变化是否要马上同步到搜索和推荐？</span></span>
<span class="line"><span>用户刚完成一次点击，是否要进入实时画像？</span></span>
<span class="line"><span>Kafka 消费积压后，指标延迟如何被发现？</span></span>
<span class="line"><span>迟到事件到达后，窗口结果是否要修正？</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这些问题的共同点是：数据不是以“每天一批文件”的形式出现，而是以持续事件流的形式出现。系统不再只处理有限历史数据，而要面对不断到来的无界数据。</p><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><blockquote><p>实时数据系统围绕事件流构建，核心问题是顺序、延迟、状态、容错和语义一致性。</p></blockquote><p>本章要建立的判断是：实时数据处理不是“把批处理跑得更快”，而是围绕事件流、事件时间、状态、窗口、容错和端到端语义重新设计数据链路。</p><p>实时系统也不是越快越好。它的设计必须在延迟、准确性、成本、复杂度、可恢复性和结果修正之间取舍。很多业务只需要分钟级实时，不需要秒级甚至毫秒级实时。</p><h2 id="机制解释" tabindex="-1">机制解释 <a class="header-anchor" href="#机制解释" aria-label="Permalink to &quot;机制解释&quot;">​</a></h2><h3 id="_8-1-kafka-事件流和数据总线" tabindex="-1">8.1 Kafka：事件流和数据总线 <a class="header-anchor" href="#_8-1-kafka-事件流和数据总线" aria-label="Permalink to &quot;8.1 Kafka：事件流和数据总线&quot;">​</a></h3><p>Kafka 是分布式事件流平台。</p><p>核心概念包括：</p><ul><li>Producer。</li><li>Consumer。</li><li>Broker。</li><li>Topic。</li><li>Partition。</li><li>Offset。</li><li>Consumer Group。</li><li>Retention。</li><li>Replication。</li><li>ISR。</li><li>Kafka Connect。</li><li>Schema Registry。</li></ul><p>Producer 写入消息，Consumer 消费消息，Broker 存储和分发消息。</p><p>Topic 是事件类别，Partition 让 Topic 可以并行写入和消费，Offset 表示消费者在分区中的读取位置。</p><p>例如订单变更事件可以进入：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>topic: order_events</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>消息可能是：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;order_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;10001&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;user_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;501&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;paid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;event_time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-04-01T10:31:20&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Kafka 的核心判断是：</p><blockquote><p>Kafka 把系统之间的直接调用，转化为可持久、可回放、可并行消费的事件流。</p></blockquote><h3 id="_8-2-kafka-在大数据链路中的角色" tabindex="-1">8.2 Kafka 在大数据链路中的角色 <a class="header-anchor" href="#_8-2-kafka-在大数据链路中的角色" aria-label="Permalink to &quot;8.2 Kafka 在大数据链路中的角色&quot;">​</a></h3><p>Kafka 在数据平台中常见角色包括：</p><ul><li>数据总线。</li><li>日志收集。</li><li>CDC 通道。</li><li>事件流。</li><li>削峰填谷。</li><li>系统解耦。</li></ul><p>例如 PostgreSQL CDC 链路：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL WAL</span></span>
<span class="line"><span>  -&gt; Logical Decoding / Replication Slot</span></span>
<span class="line"><span>  -&gt; Debezium</span></span>
<span class="line"><span>  -&gt; Kafka Topic</span></span>
<span class="line"><span>  -&gt; Flink / ClickHouse / Doris / Iceberg</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这里的 WAL 不是为 Kafka 专门生成的事件日志，而是 PostgreSQL 可靠性和恢复机制的一部分。CDC 工具通过 Logical Decoding 读取 WAL 中的持久变更，再借助 Replication Slot 记录消费进度。slot 可以让消费者恢复读取，但也意味着下游长期落后时源库可能保留更多 WAL，因此实时链路必须监控 slot 延迟、WAL 占用和消费健康。</p><p>Kafka 的价值不是“更快传消息”这么简单。</p><p>它让多个下游可以独立消费同一份变更：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>实时看板消费订单事件</span></span>
<span class="line"><span>风控系统消费支付事件</span></span>
<span class="line"><span>搜索系统消费商品变更</span></span>
<span class="line"><span>数仓系统消费业务变更</span></span>
<span class="line"><span>AI 特征系统消费用户行为</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这让系统解耦，但也带来 schema 管理、重复消费、顺序保证、积压处理和数据一致性问题。</p><h3 id="_8-3-flink-有状态流计算" tabindex="-1">8.3 Flink：有状态流计算 <a class="header-anchor" href="#_8-3-flink-有状态流计算" aria-label="Permalink to &quot;8.3 Flink：有状态流计算&quot;">​</a></h3><p>Kafka 保存事件流，Flink 处理事件流。</p><p>Flink 核心概念包括：</p><ul><li>Stream Processing。</li><li>Flink SQL。</li><li>DataStream API。</li><li>Event Time。</li><li>Processing Time。</li><li>Watermark。</li><li>Window。</li><li>State。</li><li>Checkpoint。</li><li>Savepoint。</li><li>Exactly Once。</li><li>Late Data。</li><li>Backpressure。</li></ul><p>实时计算难在状态。</p><p>例如统计最近 5 分钟支付成功订单数，系统必须持续维护窗口内状态：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事件进入</span></span>
<span class="line"><span>  -&gt; 按 event_time 分配窗口</span></span>
<span class="line"><span>  -&gt; 更新窗口状态</span></span>
<span class="line"><span>  -&gt; 到达水位线后输出结果</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Event Time 是事件真实发生时间。</p><p>Processing Time 是系统处理事件的时间。</p><p>Watermark 用来表示事件时间已经推进到某个时间点，窗口算子据此判断什么时候可以关闭或输出结果。它不是“迟到事件绝不会再来”的保证，而是系统基于数据流进展做出的有限等待声明；如果后续仍有时间戳早于或等于水位线的事件到达，就需要按迟到数据策略处理。</p><p>迟到数据 Late Data 会让结果修正变复杂。</p><p>因此，Event Time 更适合表达业务发生时间，Processing Time 延迟更低但更容易受消息到达速度、算子处理速度和故障恢复影响。实时系统选择哪种时间语义，本质是在业务口径、延迟和确定性之间取舍。</p><p>Flink 的核心判断是：</p><blockquote><p>Flink 不只是实时跑 SQL，而是在持续事件流上维护状态、窗口和容错。</p></blockquote><h3 id="_8-4-exactly-once-的价值与成本" tabindex="-1">8.4 Exactly Once 的价值与成本 <a class="header-anchor" href="#_8-4-exactly-once-的价值与成本" aria-label="Permalink to &quot;8.4 Exactly Once 的价值与成本&quot;">​</a></h3><p>Exactly Once 常被误解成“绝对不会重复”。</p><p>更准确地说，它是一种端到端处理语义：在失败恢复后，计算结果表现得像每条数据只影响一次结果。</p><p>要实现它，需要多个环节配合：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Source 可重放</span></span>
<span class="line"><span>  -&gt; Flink Checkpoint</span></span>
<span class="line"><span>  -&gt; 状态一致快照</span></span>
<span class="line"><span>  -&gt; Sink 支持事务或幂等写入</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>如果 Sink 不支持事务或幂等，即使 Flink 内部状态一致，外部结果也可能重复写。</p><p>所以 Exactly Once 的核心判断是：</p><blockquote><p>Exactly Once 是端到端系统设计，不是某个组件单独开关。</p></blockquote><p>它有价值，也有成本：更复杂的状态管理、更高延迟、更重的 checkpoint、更严格的 sink 语义。</p><h3 id="_8-5-典型实时链路" tabindex="-1">8.5 典型实时链路 <a class="header-anchor" href="#_8-5-典型实时链路" aria-label="Permalink to &quot;8.5 典型实时链路&quot;">​</a></h3><p>典型 PostgreSQL CDC 实时数仓链路是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL CDC</span></span>
<span class="line"><span>  -&gt; Debezium</span></span>
<span class="line"><span>  -&gt; Kafka</span></span>
<span class="line"><span>  -&gt; Flink SQL</span></span>
<span class="line"><span>  -&gt; ClickHouse / Doris / Iceberg</span></span>
<span class="line"><span>  -&gt; 实时 Dashboard</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这条链路中：</p><ul><li>PostgreSQL 负责记录业务事实。</li><li>Debezium 基于 PostgreSQL Logical Decoding / Replication Slot 捕获变更。</li><li>Kafka 承接和分发事件。</li><li>Flink 计算实时指标。</li><li>ClickHouse / Doris / Iceberg 承载查询或分析存储。</li><li>Dashboard 展示实时结果。</li></ul><p>每一层都有边界。Kafka 不负责复杂计算，Flink 不负责长期分析存储，ClickHouse 不负责捕获源库变更。</p><h3 id="深度展开-实时数据处理如何落到真实系统" tabindex="-1">深度展开：实时数据处理如何落到真实系统 <a class="header-anchor" href="#深度展开-实时数据处理如何落到真实系统" aria-label="Permalink to &quot;深度展开：实时数据处理如何落到真实系统&quot;">​</a></h3><p>本节补齐本章的工程细节。阅读时不要只记住概念名称，而要把它放回“输入是什么、处理路径是什么、输出给谁、边界在哪里、如何验证”的链路中。</p><h4 id="一、它从什么问题开始" tabindex="-1">一、它从什么问题开始 <a class="header-anchor" href="#一、它从什么问题开始" aria-label="Permalink to &quot;一、它从什么问题开始&quot;">​</a></h4><p>有些业务问题不是“昨天发生了什么”，而是“现在正在发生什么”，这要求持续处理事件流。</p><p>这个问题通常不会以技术名词出现，而是以业务现象出现：报表变慢、指标不一致、实时看板延迟、RAG 召回不稳定、数据无法追溯、项目 Demo 无法验收。能不能把现象还原成系统问题，是本书要训练的第一层能力。</p><h4 id="二、输入数据和前置判断" tabindex="-1">二、输入数据和前置判断 <a class="header-anchor" href="#二、输入数据和前置判断" aria-label="Permalink to &quot;二、输入数据和前置判断&quot;">​</a></h4><p>输入是订单状态变更、支付事件、用户行为、库存变化、CDC 日志和 Kafka Topic。</p><p>在动手之前，至少要确认四件事：</p><table tabindex="0"><thead><tr><th>判断项</th><th>要回答的问题</th></tr></thead><tbody><tr><td>数据粒度</td><td>一行代表什么事实，是用户、订单、订单明细、事件、文件、Chunk，还是一条关系？</td></tr><tr><td>时间边界</td><td>使用创建时间、更新时间、支付时间、事件时间，还是处理时间？</td></tr><tr><td>状态边界</td><td>哪些状态算有效，哪些测试、取消、退款、重复或迟到数据要排除？</td></tr><tr><td>责任边界</td><td>这个环节负责记录事实、生产指标、加速查询、治理质量，还是服务 AI 应用？</td></tr></tbody></table><h4 id="三、处理路径" tabindex="-1">三、处理路径 <a class="header-anchor" href="#三、处理路径" aria-label="Permalink to &quot;三、处理路径&quot;">​</a></h4><p>处理路径是从 Source 读取事件，用事件时间、水位线、窗口和状态管理进行计算，通过 checkpoint 保证恢复，再写入 OLAP、缓存、告警或实时看板。</p><p>这条路径应该能被写成可执行流程，而不是停留在术语解释。一个合格的设计至少要说明：数据从哪里来、经过哪些转换、写到哪里、谁消费、失败后如何重跑、结果如何校验。</p><h4 id="四、在真实平台中的位置" tabindex="-1">四、在真实平台中的位置 <a class="header-anchor" href="#四、在真实平台中的位置" aria-label="Permalink to &quot;四、在真实平台中的位置&quot;">​</a></h4><p>真实平台中 Kafka 承接事件流，Flink 负责有状态计算，ClickHouse、Doris、Redis 或 Elasticsearch 承接实时结果，监控系统跟踪延迟和积压。</p><p>平台位置决定了它和前后系统的关系。不要孤立地问“这个技术好不好”，而要问：</p><ul><li>它继承了上一层什么问题？</li><li>它把什么复杂度转移给了下一层？</li><li>它的输出是否能被复用、追溯和治理？</li><li>它是否改变了数据粒度、延迟、一致性或权限边界？</li></ul><h4 id="五、边界和失败模式" tabindex="-1">五、边界和失败模式 <a class="header-anchor" href="#五、边界和失败模式" aria-label="Permalink to &quot;五、边界和失败模式&quot;">​</a></h4><p>实时系统降低延迟，但增加乱序、重复、状态膨胀、回放和一致性复杂度。不是所有报表都需要实时，能接受 T+1 的任务通常优先批处理。</p><p>常见失败信号可以这样检查：</p><table tabindex="0"><thead><tr><th>失败信号</th><th>应该追问什么</th></tr></thead><tbody><tr><td>运营需要分钟级监控</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>事件到达顺序和发生顺序不一致</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>Kafka Lag 持续升高</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr><tr><td>窗口结果需要修正迟到数据</td><td>定位到具体输入、口径、链路、边界或治理责任。</td></tr></tbody></table><h4 id="六、可操作练习" tabindex="-1">六、可操作练习 <a class="header-anchor" href="#六、可操作练习" aria-label="Permalink to &quot;六、可操作练习&quot;">​</a></h4><p>为支付成功事件设计 5 分钟 GMV 实时统计，写清事件时间字段、窗口长度、水位线、迟到处理、状态 TTL 和输出表。</p><p>练习完成后不要只看“有没有跑通”，还要补一份复盘：</p><ul><li>输入数据是否足以支撑问题？</li><li>口径和边界是否写清楚？</li><li>结果能否被重复计算和对账？</li><li>如果数据量扩大 10 倍，瓶颈会出现在哪里？</li><li>如果接入下游 BI、RAG 或治理系统，还缺哪些元数据？</li></ul><h2 id="系统位置" tabindex="-1">系统位置 <a class="header-anchor" href="#系统位置" aria-label="Permalink to &quot;系统位置&quot;">​</a></h2><h3 id="实时链路设计清单" tabindex="-1">实时链路设计清单 <a class="header-anchor" href="#实时链路设计清单" aria-label="Permalink to &quot;实时链路设计清单&quot;">​</a></h3><p>实时系统最容易被误解为“延迟越低越好”。真正的实时设计要同时说明延迟、准确性、修正机制和最终对账。</p><table tabindex="0"><thead><tr><th>设计项</th><th>必须说明</th><th>常见风险</th></tr></thead><tbody><tr><td>事件定义</td><td>事件名、主键、业务时间、状态变化和幂等键</td><td>同一业务动作被拆成多个不可对账事件</td></tr><tr><td>时间语义</td><td>使用 event time、processing time，还是 ingestion time</td><td>窗口结果和业务发生时间不一致</td></tr><tr><td>Watermark</td><td>允许多晚的数据进入窗口，迟到数据如何修正</td><td>看板先出错，后续没有补偿机制</td></tr><tr><td>状态管理</td><td>Keyed state 保存什么，TTL 多久，状态如何膨胀</td><td>长期运行后状态无限增长</td></tr><tr><td>Checkpoint</td><td>多久做一次，失败从哪里恢复</td><td>任务失败后重复计算或丢失进度</td></tr><tr><td>Sink 幂等</td><td>写 ClickHouse、Doris、Redis 或 Kafka 时如何去重</td><td>重启后重复写入，实时 GMV 翻倍</td></tr><tr><td>离线对账</td><td>实时结果和离线结果按什么口径对齐</td><td>实时看板和财务报表长期冲突</td></tr></tbody></table><p>以“实时支付 GMV”为例，链路应该明确：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事件：order_status_changed</span></span>
<span class="line"><span>幂等键：event_id 或 order_id + status + version</span></span>
<span class="line"><span>事件时间：paid_at</span></span>
<span class="line"><span>窗口：按 1 分钟和 1 天同时聚合</span></span>
<span class="line"><span>迟到处理：允许 30 分钟内修正窗口，超过后进入补偿任务</span></span>
<span class="line"><span>Sink：按 dt + window_start + channel + category 写 ReplacingMergeTree</span></span>
<span class="line"><span>对账：每日用离线 DWD 支付明细重算，生成差异报告</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这说明实时计算不替代离线结算。它解决“更早看到变化”的问题，不解决“所有历史结果永远一次正确”的问题。</p><p>实时处理位于数据平台的事件流和流式计算层。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL CDC / App Events / Logs</span></span>
<span class="line"><span>  -&gt; Kafka</span></span>
<span class="line"><span>  -&gt; Flink</span></span>
<span class="line"><span>  -&gt; ClickHouse / Doris / Iceberg / Redis</span></span>
<span class="line"><span>  -&gt; 实时看板 / 风控 / 特征 / 告警 / AI 应用</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>它承接第 6 章的 CDC 链路，也补足第 7 章批处理的时效性边界。批处理擅长稳定回算和历史加工，实时处理擅长低延迟感知、持续状态计算和事件驱动。</p><p>实时处理还会引出第 9 章 OLAP 数据库：实时计算产出的结果需要被快速查询、聚合和展示，通常会写入 ClickHouse、Doris 等分析存储，或者写入湖仓表供后续批流统一分析。</p><h2 id="场景案例" tabindex="-1">场景案例 <a class="header-anchor" href="#场景案例" aria-label="Permalink to &quot;场景案例&quot;">​</a></h2><p>设计一个实时订单看板时，不应只画“Kafka -&gt; Flink -&gt; ClickHouse”三个框，而要定义事件语义。</p><p>订单支付事件可以定义为：</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;event_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;evt_10001_paid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;order_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;10001&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;user_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;501&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;event_type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;order_paid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;amount&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">299.00</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;event_time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-04-01T10:31:20&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;source&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;postgres_cdc&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>实时计算链路：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL payments</span></span>
<span class="line"><span>  -&gt; Debezium 捕获支付状态变更</span></span>
<span class="line"><span>  -&gt; Kafka topic: order_payment_events</span></span>
<span class="line"><span>  -&gt; Flink 按 event_time 做 1 分钟滚动窗口</span></span>
<span class="line"><span>  -&gt; 输出每分钟支付订单数、支付 GMV、失败订单数</span></span>
<span class="line"><span>  -&gt; ClickHouse 承载 Dashboard 查询</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这里要做几个机制判断：</p><ul><li>使用 <code>event_time</code> 而不是处理时间，避免上游延迟影响业务时间口径。</li><li>设置 Watermark，允许一定迟到事件进入正确窗口。</li><li>Sink 写入要支持幂等或去重，避免故障恢复后重复写入。</li><li>Dashboard 展示实时值时，要标注延迟和修正语义，避免把近实时结果误当最终财务口径。</li></ul><p>最终财务 GMV 仍然应由批处理链路对账确认，实时 GMV 用于监控和快速决策。</p><h2 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h2><p><strong>误区一：实时就是越快越好。</strong></p><p>实时系统要在延迟、准确性、成本和复杂度之间取舍。秒级不一定比分钟级更好。</p><p><strong>误区二：Kafka 等于实时计算。</strong></p><p>Kafka 是事件流平台，不是计算引擎。计算需要 Flink、Spark Streaming 或其他处理系统。</p><p><strong>误区三：Flink SQL 和普通 SQL 一样。</strong></p><p>Flink SQL 面对的是无界流，需要理解时间、窗口、状态、水位线和迟到数据。</p><p><strong>误区四：Kafka 保存了消息就等于数据不会丢。</strong></p><p>Kafka 提供持久化和副本机制，但端到端不丢还取决于生产者确认、Topic 配置、消费者提交 offset、下游写入和故障恢复。</p><p><strong>误区五：实时指标可以直接替代离线指标。</strong></p><p>实时指标通常有延迟、迟到修正和去重语义。财务、结算和正式经营复盘仍需要离线链路做最终对账。</p><h2 id="实战任务" tabindex="-1">实战任务 <a class="header-anchor" href="#实战任务" aria-label="Permalink to &quot;实战任务&quot;">​</a></h2><p>设计一个实时订单看板：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PostgreSQL orders</span></span>
<span class="line"><span>  -&gt; Debezium</span></span>
<span class="line"><span>  -&gt; Kafka order_events</span></span>
<span class="line"><span>  -&gt; Flink SQL</span></span>
<span class="line"><span>  -&gt; ClickHouse realtime_order_metrics</span></span>
<span class="line"><span>  -&gt; Dashboard</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>要求定义：</p><ul><li>事件结构。</li><li>Topic 设计。</li><li>窗口粒度。</li><li>Event Time 字段。</li><li>Watermark 策略。</li><li>迟到数据处理方式。</li><li>输出指标。</li></ul><p>补充要求：</p><ul><li>定义事件唯一键，说明如何去重。</li><li>定义消费延迟告警，例如 Kafka lag 或 Flink checkpoint 延迟。</li><li>说明 Sink 如何保证幂等写入。</li><li>说明实时指标如何与批处理 T+1 指标对账。</li><li>写出一条迟到数据处理策略：丢弃、修正历史窗口，或进入补偿流。</li></ul><p>示例输出指标：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>minute_time</span></span>
<span class="line"><span>paid_order_count</span></span>
<span class="line"><span>paid_gmv</span></span>
<span class="line"><span>failed_payment_count</span></span>
<span class="line"><span>unique_paid_users</span></span>
<span class="line"><span>processing_delay_seconds</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="小结引出下一章" tabindex="-1">小结引出下一章 <a class="header-anchor" href="#小结引出下一章" aria-label="Permalink to &quot;小结引出下一章&quot;">​</a></h2><p>实时数据系统把业务变化从数据库中持续捕获出来，进入事件流，再通过有状态计算生成实时结果。</p><p>Kafka 负责事件流，Flink 负责状态计算。</p><p>下一章进入 OLAP 数据库。</p><p>因为无论数据来自批处理还是实时流，最终都需要一个适合高性能分析查询的系统承载结果。</p>`,132))])}const g=i(r,[["render",d]]);export{m as __pageData,g as default};
